// ── Extract all filter params from Retell tool call body ──────────────
// Retell sends the tool parameters as top-level JSON fields in POST body
const body = $input.item.json.body || $input.item.json;

// String filters
const model      = (body.model      || '').trim();
const body_style = (body.body_style || '').trim();
const trim_level = (body.trim       || '').trim();
const color      = (body.color      || '').trim();
const fuel_type  = (body.fuel_type  || '').trim();
const condition  = (body.condition  || '').trim(); // 'New' or 'Used'

// Numeric range filters
const min_price   = body.min_price   ? parseFloat(body.min_price)   : null;
const max_price   = body.max_price   ? parseFloat(body.max_price)   : null;
const min_year    = body.min_year    ? parseInt(body.min_year)      : null;
const max_year    = body.max_year    ? parseInt(body.max_year)      : null;
const max_mileage = body.max_mileage ? parseFloat(body.max_mileage) : null;

// ── Build PostgREST query string ──────────────────────────────────────
// Supabase REST API operators:
//   ilike.*term*  = case-insensitive CONTAINS
//   eq.value      = exact match
//   gte.value     = greater than or equal
//   lte.value     = less than or equal
const parts = [
  'select=*',
  'order=msrp_numeric.asc.nullslast',
  'limit=10'
];

// Text / partial-match filters
if (model)      parts.push('model=ilike.*'          + encodeURIComponent(model)      + '*');
if (body_style) parts.push('body_style=ilike.*'     + encodeURIComponent(body_style) + '*');
if (trim_level) parts.push('trim=ilike.*'           + encodeURIComponent(trim_level) + '*');
if (color)      parts.push('exterior_color=ilike.*' + encodeURIComponent(color)      + '*');
if (fuel_type)  parts.push('fuel_type=ilike.*'      + encodeURIComponent(fuel_type)  + '*');

// Exact condition match
if (condition) parts.push('condition=eq.' + encodeURIComponent(condition));

// Numeric range filters
if (min_price)   parts.push('msrp_numeric=gte.' + min_price);
if (max_price)   parts.push('msrp_numeric=lte.' + max_price);
if (min_year)    parts.push('year=gte.'         + min_year);
if (max_year)    parts.push('year=lte.'         + max_year);
if (max_mileage) parts.push('mileage=lte.'      + max_mileage);

// Detect if caller is clearly looking for something specific
const has_filters = !!(model || body_style || trim_level || color || fuel_type ||
                       condition || min_price || max_price || min_year || max_year || max_mileage);

return [{
  json: {
    query_string: parts.join('&'),
    filters: { model, body_style, trim_level, color, fuel_type, condition,
               min_price, max_price, min_year, max_year, max_mileage },
    has_filters
  }
}];

// ── Guard: handle Supabase error responses before format step ─────────
// Supabase returns error objects like { code, message, details, hint }
// when credentials are wrong, table doesn't exist, or query is malformed.
// We catch that here so Format Voice Response always gets a clean array.

const allItems = $input.all();

// Check if first item looks like a Supabase error
const first = allItems[0] && allItems[0].json;
if (first && (first.code || first.message) && !first.vin) {
  // It's an error object — return a graceful fallback
  const errMsg = first.message || first.code || 'unknown error';
  console.error('Supabase query error:', errMsg);
  return [{
    json: {
      _supabase_error: true,
      error_message: errMsg,
      inventory_context: "I'm having a little trouble pulling up our live inventory right now. Our team can give you the most accurate information — shall I have someone reach out to you directly?",
      count: 0
    }
  }];
}

// All good — pass items through unchanged
return allItems;

// ── Short-circuit if upstream guard already set inventory_context ──────
const allItems = $input.all();
const first = allItems[0] && allItems[0].json;

if (first && first._supabase_error) {
  // Pass through the error fallback message directly
  return [{ json: first }];
}

// ── Collect all vehicle items returned by Supabase ────────────────────
const vehicles = allItems
  .map(item => item.json)
  .filter(v => v && v.vin && typeof v.vin === 'string');

const count = vehicles.length;

// ── NO RESULTS ────────────────────────────────────────────────────────
if (count === 0) {
  return [{
    json: {
      inventory_context: "I wasn't able to find any vehicles matching those exact specifications in our current inventory. Our inventory refreshes every four hours, and our team also has access to incoming units not yet listed online. I'd love to connect you with one of our sales advisors who can give you a complete picture — would that work for you?",
      count: 0
    }
  }];
}

// ── FORMAT RESULTS INTO SPEAKABLE VOICE RESPONSE ─────────────────────
const ordinals = ['first', 'second', 'third', 'fourth', 'fifth'];

let response = count === 1
  ? 'I found one vehicle that matches what you are looking for. '
  : `Great news — I found ${count} vehicle${count > 1 ? 's' : ''} that match your request. `;

vehicles.slice(0, 5).forEach((v, i) => {
  const price = v.msrp_numeric
    ? '$' + Number(v.msrp_numeric).toLocaleString('en-US')
    : (v.msrp && v.msrp !== 'N/A' ? v.msrp : 'call for pricing');

  const color     = v.exterior_color || 'showroom color';
  const trim      = v.trim ? ' ' + v.trim : '';
  const year      = v.year || '';
  const model     = v.model || 'Mercedes-Benz';
  const condLabel = (v.condition === 'New') ? 'brand new' : 'pre-owned';
  const fullLabel = `${condLabel} ${year} ${model}${trim}`.trim();

  const isLast = i === Math.min(count, 5) - 1;

  if (i === 0) {
    response += `The ${ordinals[i]} is a ${fullLabel} in ${color}, priced at ${price}. `;
  } else if (isLast && count <= 5) {
    response += `And the ${ordinals[i]} is a ${color} ${v.trim || model} at ${price}. `;
  } else {
    response += `The ${ordinals[i]} is a ${color} ${v.trim || model} at ${price}. `;
  }
});

if (count > 5) {
  const extra = count - 5;
  response += `We also have ${extra} more option${extra > 1 ? 's' : ''} available. `;
}

response += 'Would you like more details on any of these, or shall I arrange for you to come in and take one for a test drive?';

return [{
  json: {
    inventory_context: response,
    count: count,
    top_matches: vehicles.slice(0, 5).map(v => ({
      vin:        v.vin,
      year:       v.year,
      model:      v.model,
      trim:       v.trim,
      color:      v.exterior_color,
      price:      v.msrp,
      mileage:    v.mileage,
      condition:  v.condition,
      body_style: v.body_style
    }))
  }
}];
